// =========================================================
// CONFIGURAÇÃO
// =========================================================
const BITRIX_WEBHOOK_URL = 'https://atacadaoled.bitrix24.com.br/rest/2647/vaoafc68g9602xzh/';
const DIAS_RETROATIVOS = 30;
const TARGET_FUNNELS = ['304', '8', '306'];
const SELECT_FIELDS = [
  'ID', 'TITLE', 'OPPORTUNITY', 'STAGE_ID', 'CATEGORY_ID',
  'DATE_CREATE', 'DATE_MODIFY', 'CLOSEDATE', 'CLOSED', 'BEGINDATE',
  'ASSIGNED_BY_ID', 'CREATED_BY_ID', 'SOURCE_ID', 'IS_NEW',
  'UF_CRM_1708526262705',
  'UF_CRM_1709557737403',
  'UF_CRM_1709557885970',
  'UF_CRM_690B56170F2F9',
  'UF_CRM_1731350457664',
  'UF_CRM_1763990651471',
  'UF_CRM_1709985139188'
];

// =========================================================
// FETCH PAGINADO
// this.helpers.httpRequest é o método oficial do n8n para
// requisições HTTP dentro do Code node.
// =========================================================
const sinceDate = new Date();
sinceDate.setDate(sinceDate.getDate() - DIAS_RETROATIVOS);
const sinceDateISO = sinceDate.toISOString();

let allDeals = [];

for (const funnelId of TARGET_FUNNELS) {
  let start = 0;
  let hasMore = true;
  let totalFunnel = 0;

  while (hasMore) {
    const requestBody = {
      start: start,
      filter: {
        CATEGORY_ID: funnelId,
        '>=DATE_CREATE': sinceDateISO
      },
      select: SELECT_FIELDS
    };

    const resp = await this.helpers.httpRequest({
      method: 'POST',
      url: BITRIX_WEBHOOK_URL + 'crm.deal.list',
      headers: { 'Content-Type': 'application/json' },
      body: requestBody,
      json: true
    });

    const deals = resp.result || [];
    allDeals = allDeals.concat(deals);
    totalFunnel += deals.length;

    if (resp.next) {
      start = resp.next;
      await new Promise(function(resolve) { setTimeout(resolve, 200); });
    } else {
      hasMore = false;
    }
  }

  console.log('Funil ' + funnelId + ': ' + totalFunnel + ' deals buscados');
}

console.log('Total raw deals: ' + allDeals.length);
return allDeals.map(function(d) { return { json: d }; });

// =========================================================
// MAPEAMENTOS
// =========================================================
const MAPA_FONTES = {
  'UC_JKGTUC': 'Prospecção', 'WEBFORM': 'Google', 'CALLBACK': 'Instagram',
  'STORE': 'Indicação Amigo', 'RC_GENERATOR': 'Indicação Profissional',
  'CALL': 'CFA', 'UC_H0VN85': 'Youtube', 'UC_F445HA': 'Vitrine/Carro',
  'UC_8OOM1P': 'Encarte/Outdoor', 'UC_GG87LP': 'Eventos', 'UC_HCJB1D': 'Facebook',
  'UC_N35K7E': 'Ativação Relac.', 'REPEAT_SALE': 'Corporativo', 'UC_Y1DNMP': 'Site',
  'Google': 'Google', 'Facebook': 'Facebook', 'Instagram': 'Instagram',
  'Indicação': 'Indicação Amigo', 'WEB': 'Site',
  'UC_JNSE1L': 'LTV', 'UC_6F33AS': 'Busca orgânica'
};

const MAPA_ESTADOS = {
  '18493':'AC','18441':'AL','18443':'AP','18445':'AM','18447':'BA',
  '18449':'CE','18451':'DF','18453':'ES','18455':'GO','18457':'MA',
  '18459':'MT','18461':'MS','18463':'MG','18465':'PA','18467':'PB',
  '18469':'PR','18471':'PE','18473':'PI','18475':'RJ','18477':'RN',
  '18479':'RS','18481':'RO','18483':'RR','18485':'SC','18487':'SP',
  '18489':'SE','18491':'TO'
};

const MAPA_VENDEDORES = {
  '2870':'Atlas Ataike','286':'Victor Jorge','70':'Raquel Freitas',
  '364':'Paulo César','254':'Samuel Souza','190':'Mateus Martins',
  '2603':'Jucelino Júnior','2647':'Nethison Rocha','52':'Yuri Queiroz',
  '166':'Matheus Freitas','100':'Renato Campos','2258':'Aderúcia Pereira',
  '2884':'Jean Souza','2860':'Janderson Guerra','2872':'Clara Iven',
  '2767':'Isabela Silva','2593':'Gabriela Lima','2581':'Amanda Gomes',
  '2415':'Ana Flavia','2888':'Vanessa Nascimento','2876':'Juan Yuri'
};

const MAPA_MOTIVO_PERDA = {
  '49438':'Preço ou Condição de Pagamento',
  '49440':'Fechou com Concorrente',
  '49442':'Mix de Produtos (Não Trabalhamos)',
  '49444':'Estoque ou Prazo de Entrega',
  '49446':'Sem Contato com Decisor',
  '49448':'Cliente Sumiu (Sem Retorno)',
  '49450':'Projeto Adiado / Desistência',
  '49452':'Demora no Nosso Atendimento'
};

const MAPA_CATEGORY_ID = {
  '8':'[Inside] Negociações SMB','126':'Sala Técnica',
  '134':'[Orçamentos] Varejo','221':'[Lojas] Lumentech',
  '304':'[Corporativo] Negociações','306':'[Lojas] Barão'
};

const IDS_VAREJO  = ['18175','44163'];
const IDS_PROJETO = ['18177','18561','18935'];
const ESTADOS_NE  = ['AL','BA','CE','MA','PB','PE','PI','RN','SE'];

// =========================================================
// HELPERS
// =========================================================
function tratarFonte(src) { return MAPA_FONTES[src] || src || 'Direto'; }
function tratarVendedor(id) { return MAPA_VENDEDORES[String(id)] || ('ID ' + id); }
function normalizarId(v) { return Array.isArray(v) ? String(v[0] || '') : String(v || ''); }
function normalizarData(iso) { return iso ? new Date(iso).toISOString() : null; }

function definingRegional(uf) {
  if (!uf || uf === 'N/I') return 'N/I';
  if (uf === 'CE') return 'Regional CE';
  if (uf === 'PI') return 'Regional PI';
  if (uf === 'SP') return 'Regional SP';
  if (ESTADOS_NE.includes(uf)) return 'Regional NE';
  return 'Regional BR';
}

function tratarStatus(deal) {
  const s = String(deal.STAGE_ID || '').toUpperCase();
  if (s.includes('WON')) return 'Ganho';
  if (s.includes('LOSE') || s.includes('LOST')) return 'Perdido';
  if (deal.CLOSED === 'Y') return 'Perdido';
  return 'Em Andamento';
}

// =========================================================
// PROCESSAR DEAL
// =========================================================
const deal = $input.item.json;

const tipoId = normalizarId(deal['UF_CRM_1708526262705']);
let segmento = 'Outros';
if (IDS_PROJETO.includes(tipoId)) segmento = 'Projeto';
else if (IDS_VAREJO.includes(tipoId)) segmento = 'Varejo';

const statusNome = tratarStatus(deal);
const uf = MAPA_ESTADOS[deal['UF_CRM_1709557737403']] || 'N/I';
const catId = String(deal.CATEGORY_ID || '');
const dataRef = deal.CLOSED === 'Y' ? (deal.CLOSEDATE || deal.DATE_CREATE) : deal.DATE_CREATE;

return {
  json: {
    id:               String(deal.ID),
    titulo:           deal.TITLE || '',
    valor:            parseFloat(deal.OPPORTUNITY) || 0,
    segmento:         segmento,
    fonte:            tratarFonte(deal.SOURCE_ID),
    uf:               uf,
    regional:         definingRegional(uf),
    motivo_perda:     MAPA_MOTIVO_PERDA[normalizarId(deal['UF_CRM_1709985139188'])] || 'N/I',
    cidade:           deal['UF_CRM_1709557885970'] || 'N/I',
    telefone:         deal['UF_CRM_1731350457664'] || 'N/I',
    status_codigo:    deal.STAGE_ID || '',
    status_nome:      statusNome,
    responsavel_nome: tratarVendedor(deal.ASSIGNED_BY_ID),
    criador_nome:     tratarVendedor(deal.CREATED_BY_ID),
    funil:            MAPA_CATEGORY_ID[catId] || catId,
    funil_id:         catId,
    is_novo:          deal.IS_NEW === 'Y',
    is_fechado:       deal.CLOSED === 'Y',
    is_ganho:         statusNome === 'Ganho',
    link_bitrix:      'https://atacadaoled.bitrix24.com.br/crm/deal/details/' + deal.ID + '/',
    link_kinbox:      deal['UF_CRM_690B56170F2F9'] || '#',
    data_criacao:     normalizarData(deal.DATE_CREATE),
    data_fechamento:  normalizarData(dataRef),
    id_lead:          deal['UF_CRM_1763990651471'] || null
  }
};

const deals = $input.all().map(function(i) { return i.json; });
console.log('Enviando ' + deals.length + ' deals para o Vercel...');
return [{ json: { deals: deals } }];
